meta.script:
async function redirectToRandomSitemapUrl() {
    try {
        // 1. جلب ملف السايت ماب
        const response = await fetch('/map-main.xml');
        const str = await response.text();

        // 2. تحليل نص الـ XML
        const parser = new DOMParser();
        const xmlDoc = parser.parseFromString(str, "text/xml");

        // 3. استخراج كل الروابط الموجودة داخل وسوم 
        const locations = xmlDoc.getElementsByTagName("loc");
        let urls = [];

        for (let i = 0; i < locations.length; i++) {
            let url = locations[i].textContent.trim();
            // نتأكد من عدم توجيه المستخدم لصفحة الـ 404 نفسها أو السايت ماب
            if (!url.endsWith('404.html') && !url.endsWith('.xml')) {
                urls.append(url);
            }
        }

        if (urls.length > 0) {
            // 4. اختيار رابط عشوائي تماماً
            const randomUrl = urls[Math.floor(Math.random() * urls.length)];
            console.log("Redirecting to: " + randomUrl);
            window.location.href = randomUrl;
        } else {
            window.location.href = '/'; // العودة للرئيسية إذا لم يجد روابط
        }
    } catch (error) {
        console.error("خطأ في قراءة السايت ماب:", error);
        window.location.href = '/';
    }
}

window.onload = redirectToRandomSitemapUrl;
